func:
// websocket in delivers msg.payload as the raw text frame.
// Binary frames (RCU LCD mirror) arrive as Buffers; we skip those.
if (Buffer.isBuffer(msg.payload)) return null;
if (typeof msg.payload !== 'string') return null;

let d;
try { d = JSON.parse(msg.payload); }
catch (e) { return null; }

msg.payload = d;

// Route by message type.
// Output 1: amplifier state
// Output 2: heartbeat (serial up/down + client count)
// Output 3: power-action result
if (d.heartbeat)         return [null, msg, null];
if (d.power_result)      return [null, null, msg];
if (d.op_status !== undefined) return [msg, null, null];
return null;

// Convert the server's state JSON to the flat shape the SPE Panel
// UI Template expects (mode, rxtx, band, pwr, atuswr, ... etc.).
const d = msg.payload;
if (!d) return null;

const pwrMap    = { L: 'Low',    M: 'Middle', H: 'Maximum' };
const pwrMaxMap = { L: 500,      M: 1000,     H: 1500      };
// 2K-FA full-scale bumps to 2000W if you have one.
if (d.model_id === '20K') {
  pwrMaxMap.L = 700; pwrMaxMap.M = 1400; pwrMaxMap.H = 2000;
}

msg.payload = {
  model:     d.model_id || '—',
  mode:      d.op_status === 'Stby' ? 'Standby' : 'Operate',
  rxtx:      d.tx_status === 'TX'   ? 'TRANSMIT' : 'RECEIVE',
  bank:      '—',                              // not exposed by server
  input:     d.input    || '—',
  band:      (d.band    || '—').toUpperCase(),
  txant:     d.tx_antenna || '—',
  rxant:     '—',                              // not exposed by server
  pwrlvl:    pwrMap[d.p_level] || d.p_level || '—',
  pwr:       parseFloat(d.p_out)   || 0,
  pwrMax:    pwrMaxMap[d.p_level]  || 1500,
  atuswr:    parseFloat(d.swr)     || 1,
  antswr:    parseFloat(d.aswr)    || 1,
  vpa:       parseFloat(d.voltage) || 0,
  ipa:       parseFloat(d.drain)   || 0,
  tempUpper: parseFloat(d.pa_temp)          || 0,
  tempLower: parseFloat(d.pa_temp_lower)    || 0,
  tempComb:  parseFloat(d.pa_temp_combiner) || 0,
  warnings:  d.warnings && d.warnings.trim() ? d.warnings : 'No Warnings',
  alarms:    d.error    && d.error.trim()   ? d.error    : 'No Alarms',
  usb:       true,
  sync:      true
};
return msg;

// Push the server's serial-link state to the USB chip on the panel.
// Partial payload — the UI Template only updates fields that are
// !== undefined, so the rest of the dashboard stays as it was.
const d = msg.payload;
if (!d) return null;
msg.payload = {
  usb: d.serial === 'up',
  sync: d.serial === 'up'
};
return msg;

// Two outputs:
//   1 (top) → WS out (commands)        — mapped WS command string
//   2 (bot) → SPE power-on script exec — Pi-side FTDI DTR/RTS pulse
// Why: WS power_on can't wake a powered-off amp (the chip's CPU is fully
// off, so the spe-remote serial link is dead). The Pi-side script
// power_spe_on.py drives the FTDI lines directly to cold-start.
const map = {
  MODE: 'oper',
  TUNE: 'tune',
  INPUT: 'input',
  ANTENNA: 'antenna',
  PWRLVL: 'power_level',
  BL_ON: 'backlight_on',
  BL_OFF: 'backlight_off',
  L_MINUS: 'l_minus',
  L_PLUS: 'l_plus',
  C_MINUS: 'c_minus',
  C_PLUS: 'c_plus',
  LEFT: 'left',
  RIGHT: 'right',
  SET: 'set',
  DISPLAY: 'display',
  BAND_MINUS: 'band_dn',
  BAND_PLUS: 'band_up',
  OFF_SPE: 'power_off'
};
if (msg.payload === 'ON_SPE') {
  return [null, msg];   // route to exec
}
const cmd = map[msg.payload];
if (!cmd) return null;
msg.payload = cmd;
return [msg, null];     // route to WS out
